B.XO=new A.a7("Uma vez por semana, fique em sil\xeancio e ou\xe7a o que a sua alma tem a dizer.","Dalai Lama")
B.WG=new A.a7("Fa\xe7a de hoje sua obra-prima.","Miyamoto Musashi")
B.Yd=new A.a7("N\xe3o busque prazer pelo prazer. N\xe3o aja movido apenas pelo interesse pessoal. Perceba o que \xe9 verdadeiro em tudo.","Miyamoto Musashi")
B.XH=new A.a7("Voc\xea s\xf3 pode lutar do jeito que pratica.","Miyamoto Musashi")
B.YL=new A.a7("A disciplina \xe9 a ponte entre metas e conquistas.","Jim Rohn")
B.Yr=new A.a7("O sucesso \xe9 a soma de pequenos esfor\xe7os repetidos dia ap\xf3s dia.","Robert Collier")
B.WD=new A.a7("N\xe3o espere. O momento nunca ser\xe1 perfeito.","Napoleon Hill")
B.Xx=new A.a7("A vida \xe9 10% o que acontece comigo e 90% como eu reajo a isso.","Charles R. Swindoll")
B.Xi=new A.a7("Sua vida n\xe3o \xe9 um acidente. \xc9 um reflexo de suas decis\xf5es.","Tony Robbins")
B.Xs=new A.a7("Comece onde voc\xea est\xe1. Use o que voc\xea tem. Fa\xe7a o que voc\xea pode.","Arthur Ashe")
B.Y3=new A.a7("Nunca confunda movimento com a\xe7\xe3o.","Ernest Hemingway")
B.Yt=new A.a7("Em tempos de mudan\xe7a, quem aprende herda o futuro. Quem sabe, descobre que est\xe1 equipado para um mundo que n\xe3o existe mais.","Eric Hoffer")
B.YC=new A.a7("Onde a disposi\xe7\xe3o existe, os meios geralmente se seguem.","George S. Patton")
B.YS=new A.a7("A melhor hora para plantar uma \xe1rvore foi h\xe1 20 anos. A segunda melhor hora \xe9 agora.","Prov\xe9rbio Chin\xeas")
B.Xg=new A.a7("N\xe3o tenha medo de crescer devagar; tenha medo de ficar parado.","Prov\xe9rbio Chin\xeas")
B.WT=new A.a7("Quando os ventos de mudan\xe7a sopram, alguns constroem muros, outros moinhos de vento.","Prov\xe9rbio Chin\xeas")
B.X3=new A.a7("Caia sete vezes, levante-se oito.","Prov\xe9rbio Japon\xeas")
B.Xh=new A.a7("Vis\xe3o sem execu\xe7\xe3o \xe9 apenas alucina\xe7\xe3o.","Thomas Edison")
B.Xw=new A.a7("O maior inimigo do conhecimento n\xe3o \xe9 a ignor\xe2ncia, mas a ilus\xe3o do conhecimento.","Stephen Hawking")
