B.Yy=new A.a7("Em algum lugar, algo incr\xedvel est\xe1 esperando para ser descoberto.","Carl Sagan")
B.X4=new A.a7("O Universo n\xe3o \xe9 obrigado a fazer sentido para voc\xea.","Neil deGrasse Tyson")
B.XY=new A.a7("Quando n\xe3o podemos mais mudar uma situa\xe7\xe3o, somos desafiados a mudar a n\xf3s mesmos.","Viktor Frankl")
B.Yi=new A.a7("Entre o est\xedmulo e a resposta h\xe1 um espa\xe7o. Nesse espa\xe7o est\xe1 o nosso poder de escolher nossa resposta.","Viktor Frankl")
